package com.example;

import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.MethodArgumentNotValidException;
import org.springframework.web.bind.annotation.ControllerAdvice;
import org.springframework.web.bind.annotation.ExceptionHandler;

import java.time.Instant;
import java.util.List;
import java.util.stream.Collectors;

@ControllerAdvice
public class GlobalExceptionHandler {

    @ExceptionHandler(MethodArgumentNotValidException.class)
    public ResponseEntity<?> handleValidation(MethodArgumentNotValidException ex) {
        List<Violation> violations = ex.getBindingResult().getFieldErrors()
            .stream()
            .map(fe -> new Violation(fe.getField(), fe.getDefaultMessage()))
            .collect(Collectors.toList());
        return ResponseEntity.badRequest().body(new ErrorBody("VALIDATION_FAILED", violations));
    }

    @ExceptionHandler(ResourceNotFoundException.class)
    public ResponseEntity<?> handleNotFound(ResourceNotFoundException ex) {
        return ResponseEntity.status(HttpStatus.NOT_FOUND)
            .body(new ErrorBody("NOT_FOUND", List.of()));
    }

    static class Violation {
        public final String field;
        public final String message;
        Violation(String field, String message) {
            this.field = field;
            this.message = message;
        }
    }

    static class ErrorBody {
        public final String code;
        public final List<Violation> violations;
        public final String timestamp;
        ErrorBody(String code, List<Violation> violations) {
            this.code = code;
            this.violations = violations;
            this.timestamp = Instant.now().toString();
        }
    }
}
